const factoresActividad = {
  sedentario:      1.2,
  ligero:          1.375,
  moderado:        1.55,
  activo:          1.725,
  muy_activo:      1.9
};
const tdee = tmb * (factoresActividad[c.nivel_actividad] || 1.375);

// ─── 3. Calorías objetivo por objetivo ───────────────────────────────────────
const ajustesCalorias = {
  perder_peso: 0.80,   // -20% déficit
  ganar_masa:  1.12,   // +12% superávit
  definicion:  0.88,   // -12% déficit leve
  mantener:    1.00
};
const cal_objetivo = Math.round(tdee * (ajustesCalorias[c.objetivo] || 1.0));

// ─── 4. Proteínas (reglas nutricionista) ─────────────────────────────────────
// Base por objetivo (g/kg)
const baseProt = {
  perder_peso: 2.2,   // preservar músculo en déficit
  ganar_masa:  1.9,   // construcción muscular
  definicion:  2.4,   // máxima preservación
  mantener:    1.8
};
let factorProt = baseProt[c.objetivo] || 1.8;
// Ajuste por edad (anti-sarcopenia)
if (c.edad >= 60) factorProt += 0.4;
else if (c.edad >= 40) factorProt += 0.2;
const proteinas_g = Math.round(c.peso_actual * factorProt);

// ─── 5. Grasas (reglas por sexo) ─────────────────────────────────────────────
// Mujeres: 1.0 g/kg (NUNCA <0.9 - salud hormonal)
// Hombres: 0.9 g/kg (NUNCA <0.7)
const factorGrasa = c.sexo === 'femenino' ? 1.0 : 0.9;
const grasas_g_calc = Math.round(c.peso_actual * factorGrasa);
const grasas_min = c.sexo === 'femenino'
  ? Math.round(c.peso_actual * 0.9)
  : Math.round(c.peso_actual * 0.7);
const grasas_g = Math.max(grasas_g_calc, grasas_min);

// ─── 6. Carbohidratos (variable de ajuste) ───────────────────────────────────
const cal_prot  = proteinas_g * 4;
const cal_grasa = grasas_g * 9;
const carbos_g  = Math.max(0, Math.round((cal_objetivo - cal_prot - cal_grasa) / 4));

// ─── 7. Distribución por comida ──────────────────────────────────────────────
const numComidas = c.comidas_diarias || 5;
// Usar nombres reales de comidas seleccionadas por el cliente
const comidasActuales = (c.comidas_seleccionadas && c.comidas_seleccionadas.length > 0)
  ? c.comidas_seleccionadas
  : numComidas <= 3 ? ['Desayuno', 'Comida', 'Cena']
  : numComidas === 4 ? ['Desayuno', 'Almuerzo', 'Comida', 'Cena']
  : ['Desayuno', 'Almuerzo', 'Comida', 'Merienda', 'Cena'];

// Porcentaje calórico por tipo de comida
const PCT_COMIDA = {
  'desayuno': 0.25, 'almuerzo': 0.15, 'comida': 0.35,
  'merienda': 0.15, 'cena': 0.25
};
const rawPcts = {};
for (const nombre of comidasActuales) {
  const key = nombre.toLowerCase();
  rawPcts[nombre] = PCT_COMIDA[key] || (key.includes('snack') ? 0.15 : 0.20);
}
const totalPct = Object.values(rawPcts).reduce((a, b) => a + b, 0);
const patronComidas = {};
for (const [n, p] of Object.entries(rawPcts)) {
  patronComidas[n] = p / totalPct;
}
const distribucionComidas = {};
const protPorComida = Math.round(proteinas_g / Object.keys(patronComidas).length);
for (const [nombre, pct] of Object.entries(patronComidas)) {
  const cal = Math.round(cal_objetivo * pct);
  const grasa = Math.round(grasas_g * pct);
  const carb = Math.max(0, Math.round((cal - protPorComida * 4 - grasa * 9) / 4));
  distribucionComidas[nombre] = { calorias: cal, proteinas: protPorComida, grasas: grasa, carbohidratos: carb };
}

// ─── 8. Notas por edad y sexo ────────────────────────────────────────────────
const notasEspeciales = [];
if (c.edad >= 60) {
