const baseProt = { perder_peso: 2.2, ganar_masa: 1.9, definicion: 2.4, mantener: 1.8 };
let factorProt = baseProt[c.objetivo] || 1.8;
if (c.edad >= 60) factorProt += 0.4;
else if (c.edad >= 40) factorProt += 0.2;
const proteinas_g = Math.round(c.peso_actual * factorProt);

const factorGrasa = c.sexo === 'femenino' ? 1.0 : 0.9;
