  : numComidas === 4 ? ['Desayuno', 'Almuerzo', 'Comida', 'Cena']
  : ['Desayuno', 'Almuerzo', 'Comida', 'Merienda', 'Cena'];

const PCT_COMIDA = { 'desayuno': 0.25, 'almuerzo': 0.15, 'comida': 0.35, 'merienda': 0.15, 'cena': 0.25 };
const rawPcts = {};
for (const nombre of comidasActuales) {
  const key = nombre.toLowerCase();
  rawPcts[nombre] = PCT_COMIDA[key] || (key.includes('snack') ? 0.15 : 0.20);
}
const totalPct = Object.values(rawPcts).reduce((a, b) => a + b, 0);
const patronComidas = {};
for (const [n, p] of Object.entries(rawPcts)) patronComidas[n] = p / totalPct;
const distribucionComidas = {};
const protPorComida = Math.round(proteinas_g / Object.keys(patronComidas).length);
for (const [nombre, pct] of Object.entries(patronComidas)) {
