const clienteData = promptData.cliente || {};
const todasAlergias = [...(clienteData.alergias || []), ...(clienteData.intolerancias || [])];

// Detectar celiaquía con más variantes (celiaco, celíaco, celiaca, celíaca, celiaquía...)
const esGlutenFree = todasAlergias.some(a => {
  const al = a.toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, ''); // quitar acentos
  return al.includes('gluten') || al.includes('celiac') || al.includes('celiaq') || al.includes('trigo');
});

if (!esGlutenFree) return [{ json: inputData }];

// Extraer texto de respuesta de Claude
let respuestaClaude;
if (inputData.content && Array.isArray(inputData.content) && inputData.content[0]?.text) {
  respuestaClaude = inputData.content[0].text;
} else if (inputData.output) { respuestaClaude = inputData.output; }
else if (inputData.text)   { respuestaClaude = inputData.text; }
else return [{ json: inputData }];

// Parsear JSON
let planDieta;
try {
  let s = respuestaClaude.trim();
  if (s.startsWith('```')) s = s.replace(/```json?\n?/g, '').replace(/```$/g, '').trim();
  planDieta = JSON.parse(s);
} catch(e) { return [{ json: inputData }]; }

// ─── Función auxiliar: ¿el texto ya es seguro? ────────────────────────────────
function esSegurito(t) {
  if (!t) return false;
  const tl = t.toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
  return tl.includes('sin gluten') || tl.includes('tamari') ||
         tl.includes('de arroz') || tl.includes('de maiz') ||
         tl.includes('certificad') || tl.includes('de garbanzo') ||
         tl.includes('de lenteja') || tl.includes('de guisante') ||
         tl.includes('de maiz') || tl.includes('de almendra') ||
         tl.includes('de coco') || tl.includes('de quinoa');
}

