const correcciones = [];

function corregirTexto(texto) {
  if (!texto || typeof texto !== 'string') return texto;
  if (esSegurito(texto)) return texto;
  let resultado = texto;
  for (const [patron, reemplazo] of SUSTITUCIONES) {
    resultado = resultado.replace(patron, (match) => {
      if (esSegurito(match)) return match;
      correcciones.push(`"${match.trim()}"=>"${reemplazo}"`);
      return reemplazo;
    });
  }
  return resultado;
}

// Aplicar a todo el plan
if (planDieta.semanas && Array.isArray(planDieta.semanas)) {
  for (const sem of planDieta.semanas) {
    for (const dia of (sem.dias || [])) {
      for (const comida of (dia.comidas || [])) {
        if (comida.nombre)      comida.nombre = corregirTexto(comida.nombre);
        if (comida.ingredientes) {
          comida.ingredientes = comida.ingredientes.map(ing => {
            if (typeof ing === 'string') return corregirTexto(ing);
            if (ing && ing.nombre) { ing.nombre = corregirTexto(ing.nombre); return ing; }
            return ing;
          });
        }
        if (comida.preparacion) {
          comida.preparacion = comida.preparacion.map(p =>
            typeof p === 'string' ? corregirTexto(p) : p
          );
        }
      }
    }
  }
}

